 "findings": [
  {
   "title": "Two verbalization styles emerge",
   "body": "Arms 0/1/2 verbalize an activation as a confident DOCUMENT-LEVEL topic plus named specifics (entities, places, dates, brands). Arm 3 verbalizes it as a TOKEN-LEVEL readout: 'fires at token X, predicts Y', plus the local syntactic role. The token-level style is faithful to what a single mid-layer activation actually encodes."
  },
  {
   "title": "Grounded-rate: evidence wins decisively",
   "body": "Independently judged and adversarially audited (n=18): arm3 evidence 0.917 with ZERO confabulations, vs control 0.556, prompt-only 0.556, filter 0.389. arm3 is the only arm that clears the noise (+0.36 over control)."
  },
  {
   "title": "Confabulation is dynamic for cosmetic fixes, seeded for structural ones",
   "body": "A prompt that tells Claude not to speculate (arm1) is washed out by RL: arm1 lands at the control's exact grounded-rate. A warm-start that changes the READOUT SIGNAL itself (arm3, evidence not context) produces a different mode that RL preserves. The warm-start fix can suffice, but only the evidence-grounded one."
  },
  {
   "title": "The discriminative filter is worse than control",
   "body": "arm2 keeps the features that most 'pay rent' (are most reconstructable). But reconstructability IS the confabulation-pays-rent signal, so the filter selects FOR confident fabrication: 0.389 grounded-rate, 6× the control's confabulation rate."
  },
  {
   "title": "FVE is a near-tie, which is the point",
   "body": "Held-out own-critic FVE: control .408, prompt .408, filter .369, evidence .378 (n=12, within noise). arm3 reaches comparable reconstruction with a far more faithful explanation. That is the plan's actual win condition: raise grounded-rate while holding FVE."
  },
  {
   "title": "Same activation, three different fabrications",
   "body": "On the held-out West-Virginia pottery document, the three confident arms invent three mutually inconsistent entities ('American Siding Co.', a 'mid-1920s Arkansas railroad', a 'Nevada cowboy entrepreneur') from the SAME vector. That the inventions disagree is itself proof the content is generated, not read. arm3 reads the literal token correctly."
  },
  {
   "title": "RL re-invents even where the warm-start was right",
   "body": "On training documents whose warm-start targets were correct (e.g. the Sonic eclipse-drink promo), the post-RL policy substitutes brand-new fabrications ('McDonald's Slurpee at a university campus', 'a Massachusetts ice cream store'). The seed text is not what survives; the policy regenerates a new fiction each time."
  }
 ],
 "teaching": [
  {
   "set": "heldout",
   "i": 2,
   "title": "West-Virginia stoneware pottery (token 'Exc')",
   "note": "Three confident arms invent three different, inconsistent entities; arm3 correctly reads 'Exc' as the start of a name (Excelsior/Excursion)."
  },
  {
   "set": "heldout",
   "i": 8,
   "title": "Surgery-textbook citation (a number/range token)",
   "note": "arm0 'Finnish archaeology', arm1 'Nestorian hermits', arm2 'French translation' — all invented, all negative FVE. arm3 reads 'the end of a number or range', the only non-catastrophic readout here."
  },
  {
   "set": "heldout",
   "i": 1,
   "title": "Asteroid Lacrimosa catalog number '17'",
   "note": "arm0/1/2 mint discoverers, years and publications absent from the text; arm3 reads the citation-number position without inventing provenance."
  },
  {
   "set": "train_warmstart",
   "i": 3,
   "title": "Sonic eclipse-drink promo (warm-start was correct)",
   "note": "t=0 targets were accurate; post-RL arm0/1/2 drift onto fresh fabrications. The within-training analogue of dynamic confabulation."
  }
 ],
 "synthesis_points": [
  "Confabulation is DYNAMIC, not seeded. The decisive evidence is arm1, the prompt-only control: changing only the warm-start instruction does nothing, because the fabrication is re-created by the RL policy at generation time, not carried over verbatim from the seed.",
  "What works is arm3, which changes the INPUT to the readout (it conditions on activation-derived evidence rather than letting the policy free-associate from context). Only the intervention that starves the generator of room to invent moves the needle; asking nicely (arm1) or filtering afterward (arm2) does not.",
  "In every training example the post-RL generation drifted off the warm-start target onto a freshly invented but topically-adjacent confabulation. The policy regenerates a new fiction rather than preserving the seed."
 ],
 "caveats": [
  "n = 18 examples per arm is small.",
  "The grounded / mixed / confabulated labels are judge-assigned (LLM judges, adversarially audited, but not a held-out ground-truth oracle).",
  "FVE is the NLA's OWN critic reconstructing its own readout (own-critic FVE) — an internal-consistency signal, not external validation. Several FVE values are near zero or negative on hard activations, exactly where confabulation is easiest.",
  "The arm3 advantage is large and directionally clean, but should be confirmed at higher n with an independent grader before being treated as settled."
 ],
 "nextsteps": [
  "Grounded-rate vs RL step across the saved checkpoints (iter_050…500) to show WHEN arm1 decayed and confirm arm3 never did.",
  "Counterfactual CF1 recall: arm3 must not have bought groundedness by going blind to rare injected features (the auditing use case). This is the remaining gate.",
  "An independent held-out eval AR (decoupled from every arm's curation) for an unbiased cross-arm FVE.",
  "If recall holds, adopt arm3's evidence-conditioned warm-start as the replacement for the paper's open recipe."
 ],
